mapper.select:
SELECT e.id, e.emp_no, e.emp_name, e.gender, e.phone, e.email, e.dept_id, d.dept_name, e.position, e.job_level, e.hire_date, e.emp_type, e.supervisor_id, s.emp_name AS supervisor_name, e.role_code FROM emp_employee e LEFT JOIN sys_department d ON e.dept_id = d.id LEFT JOIN emp_employee s ON e.supervisor_id = s.id WHERE e.is_deleted = 0
AND e.emp_name LIKE CONCAT('%', #{empName}, '%')
AND e.dept_id = #{deptId}
AND e.role_code = #{roleCode}
ORDER BY e.id DESC
